const getSusInfo = (node, parentNode, opts) => {
  const n = (node.processName || "").toLowerCase();
  const pn = (parentNode?.processName || "").toLowerCase();
  const cmd = node.cmdLine || "";
  const img = node.image || "";
  const nBase = n.replace(/\.exe$/, "");
  const pnBase = pn.replace(/\.exe$/, "");
  const disabled = opts?.disabledRules;
  const il = img.toLowerCase();
  const pil = (parentNode?.image || "").toLowerCase();
  // Allowlist check — name must match, then: vendor path OR command-line test
  const _alEntries = PI_ALLOWLIST.get(nBase);
  let _alEntry = null;
  let _allowlisted = false;
  if (_alEntries) {
    for (const ae of _alEntries) {
      if (ae.paths && ae.paths.some(p => il.includes(p))) { _alEntry = ae; _allowlisted = true; break; }
      if (ae.cmdTest && ae.cmdTest.test(cmd)) { _alEntry = ae; _allowlisted = true; break; }
    }
  }
  const evidence = [];
  // 1. Chain evidence (no early return — collect alongside standalone)
  if (pnBase) {
    const chainHit = CHAIN_RULE_MAP.get(pnBase + ":" + nBase);
    if (chainHit) {
      const ruleId = _classifyChain(pnBase, nBase);
      if (!disabled?.has(ruleId)) {
        const _chainBeh = ruleId === "pi-0" ? "shell-exec" : ruleId === "pi-1" ? "script-exec" : ruleId === "pi-2" ? "service-exec" : "shell-exec";
        evidence.push({ cat: "chain", level: chainHit.level, reason: chainHit.reason, ruleId, tid: chainHit.techniques, beh: _chainBeh });
      }
    }
  }
  // 2. All standalone + context checks — [ruleId, testFn, defaultLevel, reason, sigCat, tid, beh]
  // testFn returns: true, { override: N }, { override: N, cat: "context" }, or false
  // sigCat: default category ("standalone" if omitted). tid: explicit technique IDs. beh: normalized behavior tag.
  const _SHELL_PARENTS = /^(cmd|powershell|pwsh|wscript|cscript|mshta|rundll32)(\.exe)?$/i;
  const _SHELL_CHILDREN = /^(cmd|powershell|pwsh|wscript|cscript|mshta|rundll32|regsvr32)(\.exe)?$/i;
  const _OFFICE_PARENTS = /^(winword|excel|powerpnt|outlook|onenote|msaccess|mspub)(\.exe)?$/i;
  const _MGMT_PARENTS = /^(ccmexec|intunemanagementextension|pdqdeployrunner|salt-minion|chef-client|puppet|taniumclient|kaceagent|automateagent|ninjaoneagent|action1_agent|lansweeper|connectwisecontrol|screenconnect\.clientservice)(\.exe)?$/i;
  const _USER_WRITABLE = /(\\temp\\|\\tmp\\|\\appdata\\|\\downloads\\|\\public\\)/i;
  const _PROG_FILES = /(\\program files\\|\\program files \(x86\)\\)/i;
  const checks = [
    ["pi-3", () => {
      if (!/^(powershell|pwsh)(\.exe)?$/i.test(n) || !ENCODED_PS.test(cmd)) return false;
      const hasStealth = /\s(-w|-windowstyle)\s+hidden\b|\s(-nop|-noprofile)\b|\s(-ep|-executionpolicy)\s+bypass\b/i.test(cmd);
      const hasCradle = /\b(iex|invoke-expression|downloadstring|net\.webclient|frombase64string)\b/i.test(cmd);
      if (_MGMT_PARENTS.test(pn) && !hasStealth && !hasCradle) return { override: 1, cat: "context" };
      if (hasStealth || hasCradle) return { override: 3 };
      return true;
    }, 2, "Encoded PowerShell", , ["T1059.001"], "script-exec"],
    ["pi-19", () => {
      if (/amsiInitFailed|amsiContext|amsi\.dll.*GetProcAddress|SetProtectionLevel/i.test(cmd)) return { override: 3 };
      if (/Set-MpPreference\s+(-Disable|-ExclusionPath|-ExclusionProcess|-ExclusionExtension)/i.test(cmd)) return { override: 3 };
      if (/Add-MpPreference\s+-Exclusion/i.test(cmd)) return { override: 3 };
      if (/\b(iex|invoke-expression)\b/i.test(cmd) && /(downloadstring|downloadfile|net\.webclient|invoke-webrequest|invoke-restmethod)/i.test(cmd)) return { override: 3 };
      if (/\[reflection\.assembly\]::load/i.test(cmd) || /\[system\.runtime\.interopservices\.marshal\]/i.test(cmd)) return { override: 3 };
      if (!/^(powershell|pwsh)(\.exe)?$/i.test(n)) return false;
      const hasIex = /\b(iex|invoke-expression)\b/i.test(cmd);
      const hasDownload = /\b(downloadstring|downloadfile|net\.webclient|invoke-webrequest|invoke-restmethod|iwr)\b/i.test(cmd);
      const hasB64 = /\bfrombase64string\b/i.test(cmd);
      const hasMem = /\bnew-object\s+io\.memorystream\b/i.test(cmd);
      const score = [hasIex, hasDownload, hasB64, hasMem].filter(Boolean).length;
      if (_MGMT_PARENTS.test(pn) && score < 3) return false;
      if (hasIex && (hasDownload || hasB64)) return true;
      if (score >= 3) return true;
      return false;
    }, 2, "PowerShell malicious semantics", , ["T1059.001"], "script-exec"],
    ["pi-4", () => CRED_DUMP_CMD.test(cmd), 3, "Credential dumping", , ["T1003"], "cred"],
    ["pi-5", () => NTDS_EXTRACT.test(cmd), 3, "NTDS extraction", , ["T1003.003"], "cred"],
    ["pi-7", () => DEFENSE_EVASION.test(cmd), 2, "Defense evasion", , ["T1070"], "evasion"],
    ["pi-21", () => {
      if (/^mshta(\.exe)?$/i.test(n) && /(https?:\/\/|javascript:|vbscript:|about:)/i.test(cmd)) return { override: 3 };
      if (/^regsvr32(\.exe)?$/i.test(n) && /(\/[sin]\b.*scrobj\.dll|https?:\/\/)/i.test(cmd)) return { override: 3 };
      if (/^rundll32(\.exe)?$/i.test(n)) {
        if (/javascript:/i.test(cmd)) return { override: 3 };
        if (/(\\temp\\|\\tmp\\|\\appdata\\|\\downloads\\|\\public\\)/i.test(cmd)) return true;
        if (/\\\\[a-z0-9_.-]+\\/i.test(cmd)) return true;
      }
      if (/^(installutil|msbuild|cmstp|regasm|regsvcs)(\.exe)?$/i.test(n) &&
        /(https?:\/\/|\\temp\\|\\tmp\\|\\appdata\\|\\downloads\\|\\public\\|\\\\[a-z0-9_.-]+\\|\/u\b|\/i:\S+)/i.test(cmd)) return true;
      if (/^forfiles(\.exe)?$/i.test(n) && /\/c\b.*(cmd|powershell|wscript|cscript|mshta|rundll32)/i.test(cmd)) return true;
      if (/^pcalua(\.exe)?$/i.test(n) && /-a\b/i.test(cmd)) return true;
      if (/^odbcconf(\.exe)?$/i.test(n) && /\/(a|f)\b/i.test(cmd)) return true;
      return false;
    }, 2, "LOLBin proxy execution", , ["T1218"], "lolbin-exec"],
    ["pi-8", () => {
      if (!ACCOUNT_MANIP.test(cmd)) return false;
      if (_MGMT_PARENTS.test(pn) && !/\b(administrators|domain\s*admins|enterprise\s*admins)\b/i.test(cmd)) return { override: 1, cat: "context" };
      if (/\b(net\s+(localgroup|group)\s+.*(administrators|domain\s*admins).*\/add)/i.test(cmd)) return { override: 3 };
      if (/\/domain\b/i.test(cmd)) return { override: 2 };
      return true;
    }, 2, "Account manipulation", , ["T1136"], "persist"],
    ["pi-20", () => {
      if (/\b(set-wminstance|__eventfilter|__eventconsumer|commandlineeventconsumer)\b/i.test(cmd)) return { override: 3 };
      if (/schtasks\b.*\/create\b.*\/s\s+\S/i.test(cmd)) return { override: 3 };
      if (/schtasks\b.*\/create\b/i.test(cmd)) {
        if (/(\\temp\\|\\tmp\\|\\appdata\\|\\downloads\\|\\public\\|powershell|cmd\.exe|mshta|rundll32|regsvr32|wscript|cscript|https?:\/\/|\\\\[a-z0-9_.-]+\\)/i.test(cmd)) return true;
        return { override: 1, cat: "context" };
      }
      if (/\bsc\s+(create|config)\b/i.test(cmd)) {
        if (/(\\temp\\|\\tmp\\|\\appdata\\|\\downloads\\|\\public\\|powershell|cmd\.exe|mshta|rundll32|regsvr32|wscript|cscript|https?:\/\/|\\\\[a-z0-9_.-]+\\)/i.test(cmd)) return true;
        return { override: 1, cat: "context" };
      }
      if (/\breg\b.*\badd\b.*\\(Run|RunOnce|Image\s*File\s*Execution\s*Options|AppInit_DLLs|Winlogon\\(Userinit|Shell))\b/i.test(cmd)) return true;
      if (/\b(register-scheduledtask|new-scheduledtask|new-service|set-service)\b/i.test(cmd)) return true;
      if (/\bset-itemproperty\b.*\\(Run|RunOnce)\b/i.test(cmd)) return true;
      if (/\bwmic\b.*\bprocess\s+call\s+create\b/i.test(cmd) && !/\/node:/i.test(cmd)) return true;
      return false;
    }, 2, "Persistence installation", , ["T1053.005", "T1543.003", "T1547.001"], "persist"],
    ["pi-9", () => {
      if (/wmic\b.*\/node:\s*\S+.*\bprocess\s+call\s+create\b/i.test(cmd)) return { override: 3 };
      if (/wmic\b.*\/node:\s*\S+.*\bshadowcopy\s+delete\b/i.test(cmd)) return { override: 3 };
      if (/winrm\s+(quickconfig|get|enumerate|set|identify)\b/i.test(cmd)) return false;
      if (/\b(invoke-command|enter-pssession|new-pssession)\b/i.test(cmd)) return { override: 3 };
      if (/wmic\b.*\/node:/i.test(cmd) || /winrm/i.test(cmd)) return { override: 1, cat: "context" };
      return false;
    }, 2, "Lateral movement command", , ["T1021"], "lateral"],
    ["pi-22", () => {
      if (/\bcertutil\b.*(-decode|-decodehex)\b/i.test(cmd)) return { override: 3 };
      if (/\bcertutil\b.*-urlcache\b/i.test(cmd) && /(https?:\/\/|\\temp\\|\\tmp\\|\\appdata\\|\\downloads\\|\\public\\|\\\\[a-z0-9_.-]+\\)/i.test(cmd)) return true;
      if (/\bbitsadmin\b.*\/transfer\b/i.test(cmd)) {
        if (/(https?:\/\/|\\temp\\|\\tmp\\|\\appdata\\|\\downloads\\|\\public\\|\\\\[a-z0-9_.-]+\\)/i.test(cmd)) return true;
        return { override: 1, cat: "context" };
      }
      if (/^curl(\.exe)?$/i.test(n) && /https?:\/\//i.test(cmd)) return { override: 1, cat: "context" };
      if (/^extrac32(\.exe)?$/i.test(n)) return { override: 1, cat: "context" };
      return false;
    }, 2, "Download/decode/stage", , ["T1105", "T1140"], "download"],
    ["pi-14", () => ARCHIVE_SUSPECT.test(cmd), 1, "Suspicious archive operation", "context", ["T1560.001"], "exfil"],
    ["pi-6", () => LSASS_TOOLS.test(n), 3, "LSASS access tool", , ["T1003.001"], "cred"],
    ["pi-10", () => AD_RECON_TOOLS.test(n), 2, "AD recon tool", , ["T1087.002"], "recon"],
    ["pi-23", () => {
      if (/\bnltest\b.*\/(dclist|domain_trusts|dsgetdc|dsgetsite|parentdomain|server)/i.test(cmd)) return true;
      if (/^dsquery(\.exe)?$/i.test(n)) return { override: 1, cat: "context" };
      if (/\bsetspn\b.*-[TQF]\b/i.test(cmd)) return true;
      if (/\bnet\s+(group|user)\b.*\/domain\b/i.test(cmd)) return { override: 1, cat: "context" };
      if (/\bwhoami\b.*\/(groups|priv|all)\b/i.test(cmd)) return { override: 1, cat: "context" };
      if (/^klist(\.exe)?$/i.test(n)) return { override: 0, cat: "context" };
      if (/\bwmic\b.*\b(useraccount|group|ntdomain)\b/i.test(cmd) && !/\/node:/i.test(cmd)) return { override: 1, cat: "context" };
      return false;
    }, 2, "Built-in AD recon", , ["T1087.002", "T1482"], "recon"],
    ["pi-11", () => NETWORK_SCANNERS.test(n), 2, "Network scanner", , ["T1046"], "recon"],
    ["pi-13", () => EXFIL_TOOLS.test(n), 2, "Exfiltration tool", , ["T1567"], "exfil"],
    ["pi-12", () => {
      if (!RMM_TOOLS.test(n)) return false;
      if (_MGMT_PARENTS.test(pn)) return { override: 1, cat: "context" };
      if (_SHELL_PARENTS.test(pn)) return true;
      if (_USER_WRITABLE.test(img)) return true;
      if (pn && !_PROG_FILES.test(img) && !/^(explorer|services|svchost)(\.exe)?$/i.test(pn)) return true;
      return false;
    }, 2, "RMM tool \u2014 suspicious context", , ["T1219"], "rmm"],
    ["pi-24", () => {
      if (/^cloudflared(\.exe)?$/i.test(n) && /\btunnel\b/i.test(cmd)) return true;
      if (/^plink(\.exe)?$/i.test(n) && /\s(-R|-L|-D)\s/i.test(cmd)) return true;
      if (/^ssh(\.exe)?$/i.test(n) && /\s(-R|-L|-D)\s/i.test(cmd)) return true;
      if (/^(frpc?|chisel|ngrok)(\.exe)?$/i.test(n) && /\b(client|server|http|tcp|start|connect|tunnel)\b/i.test(cmd)) return true;
      if (/\b(cloudflared\s+tunnel|chisel\s+(client|server)|ngrok\s+(http|tcp))\b/i.test(cmd)) return true;
      return false;
    }, 2, "Tunnel/proxy/reverse forward", , ["T1572", "T1090"], "rmm"],
    ["pi-25", () => {
      if (!/^(powershell|pwsh)(\.exe)?$/i.test(n)) return false;
      const hasEncoded = /\s(-e|-enc|-encodedcommand|-en|-ec)\b/i.test(cmd);
      const hasHidden = /\s(-w|-windowstyle)\s+hidden\b/i.test(cmd);
      const hasNoProfile = /\s(-nop|-noprofile)\b/i.test(cmd);
      const hasBypass = /\s(-ep|-executionpolicy)\s+bypass\b/i.test(cmd);
      const hasCradle = /\b(iex|invoke-expression|frombase64string)\b/i.test(cmd);
      if (hasEncoded && (hasHidden || hasNoProfile || hasBypass || hasCradle)) return { override: 3 };
      // No encoded command: only flag when stealth + cradle appears under shell/script parent
      const stealthCount = [hasHidden, hasNoProfile, hasBypass].filter(Boolean).length;
      if (!hasEncoded && hasCradle && stealthCount >= 2 && _SHELL_PARENTS.test(pn)) return true;
      return false;
    }, 2, "PowerShell stealth flag combo", , ["T1059.001", "T1027"], "script-exec"],
    ["pi-26", () => {
      if (!/^services(\.exe)?$/i.test(pn)) return false;
      // High-confidence: service launching shell/proxy binaries from writable paths
      if (_USER_WRITABLE.test(il) && _SHELL_CHILDREN.test(n)) return { override: 3 };
      // Lower-confidence context: service launched from writable path but non-shell binary
      if (_USER_WRITABLE.test(il)) return { override: 1, cat: "context" };
      return false;
    }, 2, "Service-launched binary from writable path", , ["T1543.003"], "service-exec"],
    ["pi-27", () => {
      if (!/^svchost(\.exe)?$/i.test(n)) return false;
      if (!il || !il.includes("\\")) return false;
      if (/\\windows\\(system32|syswow64)\\svchost\.exe$/i.test(il)) return false;
      return { override: 3 };
    }, 3, "svchost path anomaly", , ["T1036"], "service-exec"],
    ["pi-28", () => {
      if (!/^wmiprvse(\.exe)?$/i.test(pn)) return false;
      if (!_SHELL_CHILDREN.test(n)) return false;
      if (/\/node:\s*\S+|invoke-command|enter-pssession|new-pssession|winrm|\\\\[a-z0-9_.-]+\\/i.test(cmd)) return { override: 3 };
      return { override: 1, cat: "context" };
    }, 2, "WMI provider spawning shell/proxy", , ["T1047", "T1021"], "lateral"],
    ["pi-29", () => {
      if (/rundll32(\.exe)?\s+.*comsvcs\.dll\s*,?\s*minidump.*\blsass\b/i.test(cmd)) return { override: 3 };
      if (/procdump(\.exe)?\s+.*\b(-ma|-mm|-mp)?\b.*\blsass\b/i.test(cmd)) {
        if (_MGMT_PARENTS.test(pn)) return { override: 1, cat: "context" };
        return { override: 3 };
      }
      return false;
    }, 3, "LSASS dump commandline pattern", , ["T1003.001"], "cred"],
    ["pi-30", () => {
      if (!_OFFICE_PARENTS.test(pn) || !_SHELL_CHILDREN.test(n)) return false;
      if (/(https?:\/\/|javascript:|vbscript:|scrobj\.dll|\/i:http|\bfrombase64string\b|\b(downloadstring|invoke-expression|iex)\b|\s-enc\b)/i.test(cmd))
        return { override: 3 };
      return false;
    }, 2, "Office child with staged payload indicators", , ["T1204.002", "T1218"], "shell-exec"],
    ["pi-15", () => /^(wscript|cscript)(\.exe)?$/i.test(n) && /(\\users\\[^\\]+\\|\\appdata\\)/i.test(img), 2, "Script from user profile", , ["T1059.005"], "script-exec"],
    ["pi-16", () => SUS_PATHS.test(img) && !SAFE_PROCS.test(n), 1, "Suspicious path", "context", ["T1204"], "path"],
    ["pi-17", () => RMM_TOOLS.test(n), 0, "Remote management tool", "context", ["T1219"], "rmm"],
  ];
  // Accumulate ALL matching evidence instead of returning on first hit
  for (const [ruleId, testFn, defaultLevel, reason, sigCat, tid, beh] of checks) {
    if (disabled?.has(ruleId)) continue;
    // Sanctioned processes: suppress context-category rules entirely
    if (_allowlisted && (sigCat === "context" || ruleId === "pi-16" || ruleId === "pi-17")) continue;
    const result = testFn();
    if (result === false) continue;
    const level = result === true ? defaultLevel : (result.override ?? defaultLevel);
    const cat = (result !== true && result.cat) || sigCat || "standalone";
    // Sanctioned + context result from a primary rule: suppress
    if (_allowlisted && cat === "context") continue;
    evidence.push({ cat, level, reason, ruleId, tid, beh });
  }
  // 3. Custom rules
  if (opts?.customRules) {
    for (let ci = 0; ci < opts.customRules.length; ci++) {
      const cr = opts.customRules[ci];
      if (cr._rx.test(cmd) || cr._rx.test(n)) {
        const sevMap = { critical: 3, high: 2, medium: 1, med: 1, low: 0 };
        const cTid = cr.technique ? [cr.technique] : [];
        const cBeh = cr.behavior || null;
        evidence.push({ cat: "standalone", level: sevMap[cr.severity] ?? 1,
          reason: `${cr.category || "Custom"} \u2014 ${cr.name}`,
          ruleId: `custom-${ci}`, tid: cTid, beh: cBeh });
      }
    }
  }
  // 4. Context signals — path/arg analysis (only if any detection exists; suppressed for allowlisted)
  if (evidence.length > 0 && !_allowlisted) {
    if (/(\\temp\\|\\tmp\\|\\appdata\\|\\downloads\\|\\public\\|\\recycle|\\perflogs\\)/i.test(il))
      evidence.push({ cat: "context", level: 0, reason: "User-writable path" });
    if (/(\\\\[a-z0-9_.-]+\\)/i.test(il))
      evidence.push({ cat: "context", level: 0, reason: "UNC path execution" });
    if (/(https?:\/\/|ftp:\/\/)/i.test(cmd))
      evidence.push({ cat: "context", level: 0, reason: "Network reference in args" });
    if (_PROG_FILES.test(il) && _PROG_FILES.test(pil))
      evidence.push({ cat: "context", level: 0, reason: "Both in Program Files", dampen: true });
    if ((pnBase === "services" && nBase === "svchost") || (pnBase === "svchost" && nBase === "wmiprvse"))
      evidence.push({ cat: "context", level: 0, reason: "Expected service chain", dampen: true });
    if (/(\/update|\/install|\/silent|\/passive|trustedinstaller|windows\s*update)/i.test(cmd))
      evidence.push({ cat: "context", level: 0, reason: "Updater/installer pattern", dampen: true });
  }
  // 4b. Sanctioned tooling state — explicit state for known DFIR/EDR/AV/RMM/update agents
  const sanctioned = _allowlisted ? { cat: _alEntry.cat, match: _alEntry.cmdTest ? "cmdline" : "path" } : null;
  if (sanctioned && evidence.length > 0) {
    evidence.push({ cat: "context", level: 0, reason: `Sanctioned ${_alEntry.cat.toUpperCase()} tool`, dampen: true });
  }
  // 5. Score from accumulated evidence
  if (!evidence.length) return { level: 0, reason: null };
  const primary = evidence.filter(e => e.cat !== "context");
  // Sanctioned + no primary evidence = fully suppressed (level 0)
  if (sanctioned && primary.length === 0) return { level: 0, reason: null, sanctioned };
  const hi = primary.filter(e => e.level >= 2).length;
  const maxLevel = Math.max(...evidence.filter(e => !e.dampen).map(e => e.level));
  // Confidence depends ONLY on primary evidence (chain + standalone), never context
  const confidence = hi >= 2 ? "confirmed"
    : hi === 1 && primary.length >= 2 ? "confirmed"
    : primary.length > 0 ? "likely"
    : "context";
  // Pick best non-context entry as primary; fall back to any non-dampen entry
  const best = (primary.length > 0 ? primary : evidence.filter(e => !e.dampen))
    .reduce((a, b) => b.level > a.level ? b : a);
  // Collect behavior tags from all evidence
  const behaviors = [...new Set(evidence.map(e => e.beh).filter(Boolean))];
  // Techniques from explicit tid fields on all entries (chain entries now have .techniques from CHAIN_RULE_MAP)
  const techniques = [...new Set(evidence.flatMap(e => e.tid || []))];
  const baseResult = {
    level: Math.max(0, Math.min(3, maxLevel)),
    confidence,
    reason: best.reason,
    primaryRuleId: best.ruleId,
    evidence,
    techniques,
    behaviors,
    sanctioned,
  };
  const analystProfile = opts?.analystProfile || PI_ANALYST_PROFILE_DEFAULT;
  const suppressionHit = (analystProfile.suppressions || []).find((entry) => _piAnalystEntryMatches(entry, node, parentNode, best.reason));
  if (suppressionHit) {
    return { ...baseResult, level: 0, reason: null, confidence: "suppressed", suppressed: suppressionHit };
  }
  const baselineHit = (analystProfile.baselines || []).find((entry) => _piAnalystEntryMatches(entry, node, parentNode, best.reason));
  if (baselineHit) {
    const loweredLevel = baseResult.level <= 1 ? 0 : baseResult.level - 1;
    return {
      ...baseResult,
      level: loweredLevel,
      confidence: loweredLevel >= 2 ? baseResult.confidence : "context",
      baselined: baselineHit,
    };
  }
  return baseResult;
};

// Classify chain hit into PI_RULES group for disabled-rule filtering
const _classifyChain = (() => {
  const OFFICE = new Set(["winword","excel","powerpnt","outlook","onenote","msaccess","mspub"]);
  const SCRIPT_P = new Set(["wscript","cscript","powershell","pwsh","cmd","mshta"]);
  const SCRIPT_C = new Set(["cmd","powershell","pwsh","wscript","cscript","bash","mshta"]);
  const SERVICE = new Set(["svchost","wmiprvse","taskeng","taskhostw","wsmprovhost","dllhost","mmc","services"]);
  return (pnBase, nBase) => {
    if (OFFICE.has(pnBase)) return "pi-0";
    if (SCRIPT_P.has(pnBase) && SCRIPT_C.has(nBase)) return "pi-1";
    if (SERVICE.has(pnBase)) return "pi-2";
    return "pi-18";
  };
})();


const _integrityShort = (raw) => {
  if (!raw) return "";
  if (/16384|System/i.test(raw)) return "System";
  if (/12288|High/i.test(raw)) return "High";
  if (/8192|Medium/i.test(raw)) return "Medium";
  if (/4096|Low/i.test(raw)) return "Low";
  if (/\b0\b|Untrusted/i.test(raw)) return "Untrusted";
  return raw.replace(/^S-1-16-\d+\s*/i, "").replace(/^.*\\/, "") || raw;
};

const _providerShort = (p) => {
  if (!p) return "";
  if (p.includes("Sysmon")) return "Sysmon";
  if (p.includes("Security-Auditing")) return "Security";
  return p.replace(/^Microsoft-Windows-/i, "");
};

const SUS_COLORS = { 3: "#f85149", 2: "#f0883e", 1: "#d29922", 0: null };
const INT_COLOR = { System: "#f85149", High: "#f0883e", Medium: "#d29922", Low: "#8b949e", Untrusted: "#6e40c9" };
const PT_ICON_STYLE = { width: 14, height: 14, verticalAlign: "middle", flexShrink: 0 };
const PT_VIEW_MODES = {
  story:  { label: "Story",  filter: "suspicious", clustered: true, incident: true },
  triage: { label: "Triage", filter: "suspicious", clustered: true },
  hunt:   { label: "Hunt",   filter: "medium+",    clustered: true },
  raw:    { label: "Raw",    filter: "all",         clustered: false },
};
const PI_ANALYST_PROFILE_DEFAULT = { version: 1, suppressions: [], baselines: [] };

const _piProcBase = (value) => String(value || "").trim().toLowerCase().replace(/^.*[/\\]/, "").replace(/\.exe$/i, "");
const _piTextNorm = (value) => String(value || "").trim().toLowerCase();
const _piFieldMatch = (expected, actual) => !expected || _piTextNorm(expected) === _piTextNorm(actual);
const _piProcMatch = (expected, actual) => !expected || _piProcBase(expected) === _piProcBase(actual);
const _piCmdMatch = (expected, actual) => !expected || _piTextNorm(actual).includes(_piTextNorm(expected));
const _ptFormatDuration = (ms) => {
  if (!ms || !Number.isFinite(ms) || ms <= 0) return "";
  const mins = Math.max(1, Math.round(ms / 60000));
  if (mins < 60) return `${mins}m`;
  const hrs = Math.floor(mins / 60);
  const rem = mins % 60;
  if (hrs < 24) return rem ? `${hrs}h ${rem}m` : `${hrs}h`;
  const days = Math.floor(hrs / 24);
  const remHrs = hrs % 24;
  return remHrs ? `${days}d ${remHrs}h` : `${days}d`;
};
const _piAnalystEntryMatches = (entry, node, parentNode, reason) => {
  if (!entry) return false;
  if (!_piFieldMatch(entry.reason, reason)) return false;
  if (!_piProcMatch(entry.processName, node?.processName || node?.image)) return false;
  if (!_piProcMatch(entry.parentProcessName, parentNode?.processName || parentNode?.image)) return false;
  if (!_piFieldMatch(entry.hostname, node?.hostname)) return false;
  if (!_piFieldMatch(entry.user, node?.user)) return false;
  if (!_piFieldMatch(entry.image, node?.image)) return false;
  if (!_piCmdMatch(entry.cmdContains, node?.cmdLine)) return false;
  return true;
};

